import React, { useState, useEffect, useRef } from "react";
import { graphql, Link, navigate } from "gatsby";
import { GatsbyImage, getImage } from "gatsby-plugin-image";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faCircleXmark } from "@fortawesome/free-solid-svg-icons";
import { SeoDefault } from "src/components/Seo";
import { LayoutProse } from "src/components/layouts/layout";
import { formatMonthYear } from "src/utils/FormatDate";
import { KeywordButtonsGeneral } from "src/utils/KeywordButtons";
import { SoftwareButtonsGeneral } from "src/utils/SoftwareButtons";

import PlaceholderImage from "src/assets/placeholder/2000x2000.png";

const pageTitle = "Search";

const sortedPTypes = [
  "Publications",
  "Projects",
  "Models",
  "Blog",
  "News",
  "Papers",
  "Archive",
];

const formatpType = (pType) =>
  ({
    pub: "Publications",
    projects: "Projects",
    models: "Models",
    blog: "Blog",
    news: "News",
    papers: "Papers",
    archive: "Archive",
  })[pType] || pType.replace(/^\w/, (c) => c.toUpperCase());

const SearchPage = ({ data, location }) => {
  const pages = data.allMdx.nodes;
  const [searchQuery, setSearchQuery] = useState(
    decodeURIComponent(location.search.replace("?q=", "")).trim(),
  );
  const searchInputRef = useRef(null);

  useEffect(() => {
    setSearchQuery(
      decodeURIComponent(location.search.replace("?q=", "")).trim(),
    );
  }, [location.search]);

  useEffect(() => {
    const handleShortcut = (event) => {
      if (event.ctrlKey && event.key === "/") {
        event.preventDefault();
        searchInputRef.current.focus();
      } else if (event.key === "Escape") {
        searchInputRef.current.value = "";
      }
    };

    window.addEventListener("keydown", handleShortcut);

    return () => {
      window.removeEventListener("keydown", handleShortcut);
    };
  }, []);

  const handleInputChange = (event) => {
    setSearchQuery(event.target.value);
  };

  const handleKeyDown = (event) => {
    if (event.key === "Enter") {
      navigate(`/search/?q=${encodeURIComponent(searchQuery)}`);
    }
  };

  const filteredPages = searchQuery
    ? pages.filter((page) => {
        // Keywords
        const keywordMatch =
          page.frontmatter.keywords?.some((keyword) =>
            keyword.name?.toLowerCase().includes(searchQuery.toLowerCase()),
          ) || false;

        // Title
        const titleMatch =
          page.frontmatter.title
            ?.toLowerCase()
            .includes(searchQuery.toLowerCase()) || false;

        // Software
        const softwareMatch =
          page.frontmatter.software?.some((software) =>
            software.name?.toLowerCase().includes(searchQuery.toLowerCase()),
          ) || false;

        // Author
        const authorMatch = Array.isArray(page.frontmatter.author)
          ? page.frontmatter.author.some((author) =>
              author.name?.toLowerCase().includes(searchQuery.toLowerCase()),
            )
          : false;

        // Publisher
        const publisherMatch =
          page.frontmatter.publisher
            ?.toLowerCase()
            .includes(searchQuery.toLowerCase()) || false;

        // Date
        const dateMatch =
          page.frontmatter.date
            ?.toLowerCase()
            .includes(searchQuery.toLowerCase()) || false;

        return (
          keywordMatch ||
          titleMatch ||
          authorMatch ||
          publisherMatch ||
          dateMatch ||
          softwareMatch
        );
      })
    : pages;

  const sortedPages = filteredPages.sort(
    (a, b) => new Date(b.frontmatter.date) - new Date(a.frontmatter.date),
  );

  const groupedPages = sortedPages.reduce((acc, page) => {
    const { p_type } = page.frontmatter;
    acc[p_type] = acc[p_type] || [];
    acc[p_type].push(page);
    return acc;
  }, {});

  const [filter] = useState("");

  const handleShowAllClick = () => {
    setSearchQuery("");
    navigate(location.pathname);
  };

  const sortedKeys = Object.keys(groupedPages).sort(
    (a, b) =>
      sortedPTypes.indexOf(formatpType(a)) -
      sortedPTypes.indexOf(formatpType(b)),
  );

  return (
    <LayoutProse pageTitle={pageTitle}>
      <main className="sea-flx">
        {/* Search box */}
        <div className="sea-input-wrp">
          <input
            type="text"
            ref={searchInputRef}
            value={searchQuery}
            onChange={handleInputChange}
            onKeyDown={handleKeyDown}
            placeholder="Enter search terms..."
            className="sea-input"
          />
          {/* Clear Button */}
          {searchQuery ? (
            <button onClick={handleShowAllClick} className="sea-btn-clr">
              <FontAwesomeIcon
                icon={faCircleXmark}
                className="sea-btn-clr-ico"
              />
            </button>
          ) : null}
        </div>

        {/* <HrRelaxed /> */}

        <section className="sea-art-wrp">
          {/* Search results */}
          <div title="" className="sea-p-res">
            {searchQuery ? (
              <>Search results:</>
            ) : (
              <>Explore all available posts:</>
            )}
          </div>

          {/* All/sorted results */}
          {sortedKeys.map(
            (p_type) =>
              (!filter || filter === formatpType(p_type)) &&
              p_type !== "null" && (
                <article id={`sea-${p_type}`} key={p_type} className="sea-art">
                  {/* pType as h3 */}
                  <h2>
                    <Link to={`/${p_type}`} className="g-hidden-link">
                      {formatpType(p_type)}{" "}
                    </Link>
                  </h2>

                  {/* Cards collection */}
                  {groupedPages[p_type]
                    .filter(
                      (node) =>
                        node.frontmatter.title &&
                        node.frontmatter.title !== "Placeholder",
                    ) // Filter out pages with null/empty or "placeholder" titles
                    .map((page) => (
                      // Cards wrapper

                      <div
                        key={page.id}
                        className="sea-bsc"
                        title={page.frontmatter.title}
                      >
                        {/* Hero image */}
                        {page.frontmatter.hero_img_src || PlaceholderImage ? (
                          <div className="sea-img-wrp">
                            <Link to={`/${p_type}/${page.frontmatter.slug}`}>
                              {page.frontmatter.hero_img_src ? (
                                <GatsbyImage
                                  image={getImage(
                                    page.frontmatter.hero_img_src,
                                  )}
                                  alt={page.frontmatter.title}
                                  className="sea-img"
                                />
                              ) : (
                                // WIP: gatsby-image-wrapper (temp use)
                                <div className="gatsby-image-wrapper sea-img">
                                  <img
                                    alt="Placeholder"
                                    src={PlaceholderImage}
                                  />
                                </div>
                              )}
                            </Link>
                          </div>
                        ) : null}

                        {/* Contents wrapper: Title & date, Author or Publisher, KeywordButtonsGeneral */}
                        <div className="sea-fm-wrp">
                          {/* Title & date */}
                          <div className="sea-tit-date-wrp">
                            {/* Title */}
                            {page.frontmatter.title ? (
                              <h4 className="sea-tit">
                                <Link
                                  to={`/${p_type}/${page.frontmatter.slug}`}
                                  className="g-hidden-link"
                                >
                                  {page.frontmatter.title}
                                </Link>
                              </h4>
                            ) : null}

                            {/* Date */}
                            {page.frontmatter.date ? (
                              <p
                                className="sea-date"
                                title={formatMonthYear(page.frontmatter.date)}
                              >
                                {formatMonthYear(page.frontmatter.date)}
                              </p>
                            ) : null}
                          </div>

                          {/* Author or Publisher (if any) */}
                          {p_type === "pub" ? (
                            <p
                              className="sea-aop"
                              title={
                                p_type === "pub" && page.frontmatter.author
                                  ? page.frontmatter.author
                                      .map((author) => author.name)
                                      .join("; ")
                                  : page.frontmatter.publisher
                              }
                            >
                              {p_type === "pub" && page.frontmatter.author
                                ? page.frontmatter.author
                                    .map((author) => author.name)
                                    .join("; ")
                                : page.frontmatter.publisher}
                            </p>
                          ) : null}

                          {/* KeywordButtonsGeneral */}
                          <KeywordButtonsGeneral
                            keywords={page.frontmatter.keywords}
                          />

                          {/* SoftwareButtonsGeneral */}
                          {p_type === "projects" && (
                            <SoftwareButtonsGeneral
                              softwares={page.frontmatter.software}
                            />
                          )}
                        </div>
                      </div>
                    ))}
                </article>
              ),
          )}
        </section>
      </main>
    </LayoutProse>
  );
};

export default SearchPage;

export const Head = () => <SeoDefault title={pageTitle} />;

export const query = graphql`
  query SearchQuery {
    allMdx {
      nodes {
        id
        frontmatter {
          title
          slug
          p_type
          date
          software {
            id
            name
          }
          keywords {
            id
            name
          }
          hero_img_src {
            childImageSharp {
              gatsbyImageData
            }
          }
          author {
            name
          }
          publisher
        }
      }
    }
  }
`;
