// SoftwareButtons.js

import React from "react";
import { Link } from "gatsby";

export const SoftwareButtonsGeneral = ({
  softwares,
  showAll,
  extraClass,
  sliceAt,
}) => {
  // Check if softwares is null or undefined, default to empty array if true
  const softwareList = softwares || [];

  const sliceNumber = sliceAt !== undefined ? sliceAt : 3;
  const slicedSoftwares = showAll
    ? softwareList
    : softwareList.slice(0, sliceNumber);

  return (
    <div className={`${"g-kw-wrp"}${extraClass ? ` ${extraClass}` : ""}`}>
      {slicedSoftwares.map((software) => (
        <Link
          to={`/search/?q=${encodeURIComponent(software.name)}`}
          className="g-kw-btn"
          key={software.id}
          title={software.name}
        >
          {software.name}
        </Link>
      ))}
    </div>
  );
};
