// KeywordButtons.js

import React from "react";
import { Link } from "gatsby";

export const KeywordButtonsGeneral = ({
  keywords,
  showAll,
  extraClass,
  sliceAt,
}) => {
  // Check if keywords is null or undefined, default to empty array if true
  const keywordList = keywords || [];

  const sliceNumber = sliceAt !== undefined ? sliceAt : 3;
  const slicedKeywords = showAll
    ? keywordList
    : keywordList.slice(0, sliceNumber);

  return (
    <div className={`${"g-kw-wrp"}${extraClass ? ` ${extraClass}` : ""}`}>
      {slicedKeywords.map((keyword) => (
        <Link
          to={`/search/?q=${encodeURIComponent(keyword.name)}`}
          className="g-kw-btn"
          key={keyword.id}
          title={keyword.name}
        >
          {keyword.name}
        </Link>
      ))}
    </div>
  );
};
